/**
 * Drip campaign sequence configuration.
 * Maps (list, day) → Listmonk transactional template ID.
 *
 * Template IDs are generated by setup_listmonk.ts and stored in environment variables.
 * Content edits: Listmonk UI → Campaigns → Templates. No code changes needed.
 */

import { listmonkConfig } from '../lib/config.js';

export interface DripStep {
  day: number;
  templateId: number;
  fromEmail?: string;
}

export interface DripSequence {
  name: string;
  listId: number;
  dateAttrib?: string;
  steps: DripStep[];
}

